import{c as t,Q as o,j as a,m as i}from"./chunks/framework.CTNaDwNv.js";const p=JSON.parse('{"title":"What is agent_api?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is.md","filePath":"guide/what-is.md","lastUpdated":1779853631000}'),r={name:"guide/what-is.md"};function s(n,e,l,d,c,u){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="what-is-agent-api" tabindex="-1">What is agent_api? <a class="header-anchor" href="#what-is-agent-api" aria-label="Permalink to &quot;What is agent_api?&quot;">​</a></h1><p><code>agent_api</code> is a single FiveM resource that exposes a <a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">Model Context Protocol (MCP)</a> server. Once installed and started, any MCP-aware coding agent — Claude Code, Codex CLI, Cursor, Cline, your own — can:</p><ul><li>read and write resource files within a sandboxed root</li><li>create, ensure, start, stop, restart, refresh resources</li><li>capture console output around any command</li><li>invoke any FiveM <strong>server</strong> native and any FiveM <strong>client</strong> native (on opted-in test subjects)</li><li>talk to ESX, ox_lib, oxmysql via dedicated tools or reflective <code>*_call_*</code> dispatchers</li><li>spawn allowlisted shell commands (<code>npm</code>, <code>npx</code>, <code>pnpm</code>, <code>vite</code>, <code>git</code>, <code>node</code>) inside a resource folder — so the agent can <code>npx create vite</code> then <code>npm run build</code> an entire UI tree</li><li>screenshot the NUI through CEF&#39;s DevTools Protocol, with the option to isolate a specific resource&#39;s iframe</li></ul><p>Everything runs in-process inside the FiveM server&#39;s CitizenJS runtime. No external Node sidecar, no Docker, no extra service to keep alive.</p><h2 id="why-it-exists" tabindex="-1">Why it exists <a class="header-anchor" href="#why-it-exists" aria-label="Permalink to &quot;Why it exists&quot;">​</a></h2><p>LLM agents are good at writing code. They&#39;re bad at running it against a stateful runtime with strong opinions — and FiveM is exactly that runtime. The friction loop without <code>agent_api</code> looks like:</p><ol><li>Agent writes a Lua file in your editor.</li><li>You alt-tab to txAdmin and <code>ensure</code> the resource.</li><li>You alt-tab back to chat to paste the console output.</li><li>You paste a screenshot of the bug.</li><li>Repeat.</li></ol><p>With <code>agent_api</code>, the agent itself does steps 2 through 4:</p><ol><li><code>write_file</code> → file lands inside the resource folder.</li><li><code>ensure_resource</code> → console lines captured and returned in the same envelope.</li><li><code>screenshot_nui</code> → PNG saved, agent reads it directly.</li></ol><p>You stay in the conversation; the agent stays at the wheel.</p><h2 id="design-tenets" tabindex="-1">Design tenets <a class="header-anchor" href="#design-tenets" aria-label="Permalink to &quot;Design tenets&quot;">​</a></h2><ul><li><strong>One resource.</strong> No sidecar process, no extra port to open, no daemon to babysit.</li><li><strong>Safe by default.</strong> Token-gated, readonly verb heuristic on every reflective call, hard blocklist for <code>DropPlayer</code>/<code>ExecuteCommand</code>/<code>StopResource</code>, sandboxed write roots, per-resource lock on mutators.</li><li><strong>Stable surface.</strong> New tools add a file under <code>src/server/tools/</code>; new plugins add a folder under <code>src/server/plugins/</code>. The error code enum is append-only.</li><li><strong>Plugin-first for frameworks.</strong> Every supported framework lives behind a <code>Plugin</code> that auto-detects via <code>GetResourceState</code> and registers its own tools. Adding QBCore or whatever comes next is a single folder + one push to <code>ALL_PLUGINS</code>.</li></ul><h2 id="what-it-is-not" tabindex="-1">What it is not <a class="header-anchor" href="#what-it-is-not" aria-label="Permalink to &quot;What it is not&quot;">​</a></h2><ul><li>Not a generic FiveM admin panel. Use txAdmin for human admin work.</li><li>Not a way to bypass a server&#39;s permissions. ACE rules still apply.</li><li>Not a replacement for source control. It writes into resource folders; commit them separately.</li><li>Not a license workaround. The PolyForm Noncommercial 1.0.0 license means non-commercial use only.</li></ul>',14)])])}const g=t(r,[["render",s]]);export{p as __pageData,g as default};
